const c = $input.first().json.contact;
const cf = (c.customFields || []).reduce((acc, f) => { acc[f.id] = f.value; return acc; }, {});

const FIELD_FOLLOW_UP_COUNT = '8AZ4Ww7zK6EdI05jpZpx';
const FIELD_LAST_FOLLOWUP_AT = 'PRvHAhpyqNvxvHU8O43f';

const followUpCount = parseInt(cf[FIELD_FOLLOW_UP_COUNT] || '0');
const lastFollowupAt = cf[FIELD_LAST_FOLLOWUP_AT] || null;

const isStalled = followUpCount >= 5;

if (!isStalled) {
  return [{ json: { skip: true, reason: 'not_stalled', follow_up_count: followUpCount } }];
}

let daysSince = 0;
if (lastFollowupAt) {
  const lastDate = new Date(lastFollowupAt);
  const ageMs = Date.now() - lastDate.getTime();
  daysSince = Math.floor(ageMs / (24 * 60 * 60 * 1000));
}

return [{
  json: {
    skip: false,
    contact_id: c.id,
    email: c.email,
    first_name: c.firstName || '',
    last_name: c.lastName || '',
    company: c.companyName || '',
    follow_up_count: followUpCount,
    last_followup_at: lastFollowupAt,
    days_since_last: daysSince
  }
}];

