const items = $input.all().map(it => it.json).filter(d => !d.skip);

if (items.length === 0) {
  return [{ json: { skip: true, count: 0 } }];
}

const LOCATION_ID = 'vBGfwhaDbMUIhHW1sYSI';

const slackLines = items.map(s => {
  const name = (s.first_name + ' ' + s.last_name).trim() || s.email;
  const company = s.company ? ' (' + s.company + ')' : '';
  const ghlUrl = 'https://app.gohighlevel.com/v2/location/' + LOCATION_ID + '/contacts/detail/' + s.contact_id;
  return '• *' + s.email + '* — ' + name + company + ' — ' + s.days_since_last + 'd since last touch\n  ' + ghlUrl;
}).join('\n\n');

const slackText = ':warning: *Stalled Leads — Action Needed* (' + items.length + ')\n\n' +
  'These leads have completed the 5-touch follow-up sequence and are sitting in AWAITING_PROSPECT.\n' +
  'Move stage to NURTURE or CLOSED_LOST when you have decided.\n\n' + slackLines;

const emailRows = items.map(s => {
  const name = (s.first_name + ' ' + s.last_name).trim() || '—';
  const ghlUrl = 'https://app.gohighlevel.com/v2/location/' + LOCATION_ID + '/contacts/detail/' + s.contact_id;
  return '<tr><td>' + s.email + '</td><td>' + name + '</td><td>' + (s.company || '—') + '</td><td>' + s.days_since_last + 'd</td><td><a href="' + ghlUrl + '">Open in GHL</a></td></tr>';
}).join('');

const emailHtml = '<div style="font-family: -apple-system, sans-serif; max-width: 720px;">' +
  '<h2 style="color: #c2410c;">⚠ Stalled Leads — ' + items.length + ' decision' + (items.length === 1 ? '' : 's') + ' needed</h2>' +
  '<p>These leads have completed the full 5-touch follow-up sequence and are sitting in <code>AWAITING_PROSPECT</code>.</p>' +
  '<p>Decide: <strong>NURTURE</strong> (revisit later) or <strong>CLOSED_LOST</strong> (give up).</p>' +
  '<table border="1" cellpadding="8" cellspacing="0" style="border-collapse: collapse; width: 100%; margin-top: 16px;">' +
  '<thead style="background: #f3f4f6;"><tr><th align="left">Email</th><th align="left">Name</th><th align="left">Company</th><th align="left">Stalled</th><th align="left">Action</th></tr></thead>' +
  '<tbody>' + emailRows + '</tbody>' +
  '</table>' +
  '<p style="color: #6b7280; font-size: 12px; margin-top: 24px;">Generated by Workflow D (Stalled Lead Reminder) — runs weekdays at 14:00.</p>' +
  '</div>';

return [{
  json: {
    skip: false,
    count: items.length,
    slack_text: slackText,
    email_html: emailHtml,
    email_subject: '[MOIC] ' + items.length + ' Stalled Lead' + (items.length === 1 ? '' : 's') + ' — Stage Decision Needed'
  }
}];
